module register_16bit(
    input clk,
    input reset,
    input enable,
    input [15:0] data_in,
    output reg [15:0] data_out
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk) begin
        if (reset)
            data_out <= 16'b0;
        else if (enable)
            data_out <= data_in;
    end
endmodule
